"use client";

import { useState, useTransition, useEffect } from "react";
import { createPortal } from "react-dom";
import { createWorkout } from "@/actions/workout-actions";

const WORKOUT_TYPES = [
    { label: "Cardio", icon: "directions_run", color: "text-blue-400", active: "border-blue-400 bg-blue-400/10" },
    { label: "Strength", icon: "fitness_center", color: "text-primary", active: "border-primary bg-primary/10" },
    { label: "Yoga", icon: "self_improvement", color: "text-green-400", active: "border-green-400 bg-green-400/10" },
    { label: "HIIT", icon: "local_fire_department", color: "text-orange-400", active: "border-orange-400 bg-orange-400/10" },
    { label: "Swimming", icon: "pool", color: "text-cyan-400", active: "border-cyan-400 bg-cyan-400/10" },
    { label: "Other", icon: "sports", color: "text-text-muted", active: "border-border-dark bg-surface-darker" },
];

export default function AddWorkoutModal() {
    const [open, setOpen] = useState(false);
    const [mounted, setMounted] = useState(false);
    const [title, setTitle] = useState("");
    const [type, setType] = useState("Cardio");
    const getLocalDateStr = () => {
        const d = new Date();
        return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
    };

    const [date, setDate] = useState(() => getLocalDateStr());
    const [startTime, setStartTime] = useState("07:00");
    const [endTime, setEndTime] = useState("08:00");
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState(false);
    const [isPending, startTransition] = useTransition();

    useEffect(() => { setMounted(true); }, []);

    function reset() {
        setTitle("");
        setType("Cardio");
        setDate(getLocalDateStr());
        setStartTime("07:00");
        setEndTime("08:00");
        setError(null);
        setSuccess(false);
    }

    function handleClose() {
        if (!isPending) { setOpen(false); reset(); }
    }

    function handleSubmit() {
        if (!title.trim()) { setError("Please enter the name of the activity."); return; }
        setError(null);
        startTransition(async () => {
            const result = await createWorkout({ title, type, date, startTime, endTime });
            if (result.success) {
                setSuccess(true);
                setTimeout(() => { setOpen(false); reset(); }, 1200);
            } else {
                setError(result.error ?? "Error");
            }
        });
    }

    const meta = WORKOUT_TYPES.find((t) => t.label === type) ?? WORKOUT_TYPES[0];

    const modalContent = (
        <div className="fixed inset-0 z-[9999] overflow-y-auto">
            {/* Backdrop */}
            <div className="fixed inset-0 bg-black/60 backdrop-blur-sm" onClick={handleClose} />
            {/* Centering wrapper */}
            <div className="flex min-h-full items-center justify-center p-4">
                <div className="relative w-full max-w-sm rounded-2xl bg-background-dark border border-border-dark shadow-2xl shadow-black/50 flex flex-col">
                    {/* Header */}
                    <div className="flex items-center justify-between px-5 py-3 border-b border-border-dark bg-surface-dark rounded-t-2xl">
                        <div className="flex items-center gap-2">
                            <span className={`material-symbols-outlined text-[18px] ${meta.color}`}>{meta.icon}</span>
                            <h2 className="text-sm font-bold text-white">Add Activities</h2>
                        </div>
                        <button onClick={handleClose} className="text-text-muted hover:text-white p-1 rounded-lg hover:bg-surface-darker transition">
                            <span className="material-symbols-outlined text-[18px]">close</span>
                        </button>
                    </div>

                    {/* Body */}
                    <div className="px-5 py-4 flex flex-col gap-3">
                        {/* Title */}
                        <div>
                            <label className="block text-xs font-semibold text-text-muted mb-1">
                                Name of Activities <span className="text-primary">*</span>
                            </label>
                            <input
                                type="text"
                                value={title}
                                onChange={(e) => setTitle(e.target.value)}
                                placeholder="Example: Morning run..."
                                className="w-full rounded-xl bg-surface-dark border border-border-dark text-white text-sm px-3 py-2 placeholder:text-text-muted focus:outline-none focus:border-primary transition"
                            />
                        </div>

                        {/* Type pills */}
                        <div>
                            <label className="block text-xs font-semibold text-text-muted mb-1">Type of Activities</label>
                            <div className="flex gap-2 overflow-x-auto pb-1" style={{ scrollbarWidth: "none" }}>
                                {WORKOUT_TYPES.map((t) => (
                                    <button
                                        key={t.label}
                                        type="button"
                                        onClick={() => setType(t.label)}
                                        className={`flex items-center gap-1.5 shrink-0 rounded-full border px-3 py-1.5 text-xs font-medium transition-all ${type === t.label
                                            ? `${t.active} ${t.color} text-white`
                                            : "border-border-dark bg-surface-dark text-text-muted hover:border-primary/40"
                                            }`}
                                    >
                                        <span className={`material-symbols-outlined text-[13px] ${type === t.label ? t.color : ""}`}>{t.icon}</span>
                                        {t.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Date */}
                        <div>
                            <label className="block text-xs font-semibold text-text-muted mb-1">Day</label>
                            <input
                                type="date"
                                value={date}
                                onChange={(e) => setDate(e.target.value)}
                                className="w-full rounded-xl bg-surface-dark border border-border-dark text-white text-sm px-3 py-2 focus:outline-none focus:border-primary transition [color-scheme:dark]"
                            />
                        </div>

                        {/* Times */}
                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className="block text-xs font-semibold text-text-muted mb-1">Start</label>
                                <input
                                    type="time"
                                    value={startTime}
                                    onChange={(e) => setStartTime(e.target.value)}
                                    className="w-full rounded-xl bg-surface-dark border border-border-dark text-white text-sm px-3 py-2 focus:outline-none focus:border-primary transition [color-scheme:dark]"
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-semibold text-text-muted mb-1">End</label>
                                <input
                                    type="time"
                                    value={endTime}
                                    onChange={(e) => setEndTime(e.target.value)}
                                    className="w-full rounded-xl bg-surface-dark border border-border-dark text-white text-sm px-3 py-2 focus:outline-none focus:border-primary transition [color-scheme:dark]"
                                />
                            </div>
                        </div>

                        {/* Feedback */}
                        {error && (
                            <div className="flex items-center gap-2 rounded-lg bg-red-500/10 border border-red-500/30 px-3 py-2">
                                <span className="material-symbols-outlined text-[15px] text-red-400">error</span>
                                <p className="text-xs text-red-400">{error}</p>
                            </div>
                        )}
                        {success && (
                            <div className="flex items-center gap-2 rounded-lg bg-green-500/10 border border-green-500/30 px-3 py-2">
                                <span className="material-symbols-outlined text-[15px] text-green-400">check_circle</span>
                                <p className="text-xs text-green-400">Activity added successfully!</p>
                            </div>
                        )}
                    </div>

                    {/* Footer */}
                    <div className="px-5 py-3 border-t border-border-dark bg-surface-dark flex gap-3 rounded-b-2xl">
                        <button
                            onClick={handleClose}
                            disabled={isPending}
                            className="flex-1 rounded-xl border border-border-dark py-2 text-sm font-medium text-text-muted hover:text-white hover:border-white/20 transition disabled:opacity-50"
                        >
                            Cancel
                        </button>
                        <button
                            onClick={handleSubmit}
                            disabled={isPending || success}
                            className="flex-1 rounded-xl bg-primary py-2 text-sm font-bold text-white shadow-lg shadow-primary/30 hover:bg-primary-dark transition disabled:opacity-50 flex items-center justify-center gap-2"
                        >
                            {isPending ? (
                                <>
                                    <span className="material-symbols-outlined text-[15px] animate-spin">progress_activity</span>
                                    Saving...
                                </>
                            ) : (
                                <>
                                    <span className="material-symbols-outlined text-[15px]">check</span>
                                    Save Activity
                                </>
                            )}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );

    return (
        <>
            {/* Trigger Button */}
            <button
                onClick={() => setOpen(true)}
                className="flex items-center gap-2 rounded-xl bg-white px-4 py-2.5 text-sm font-bold text-background-dark shadow-md hover:bg-gray-100 transition-all"
            >
                <span className="material-symbols-outlined text-[20px]">add</span>
                <span className="hidden sm:inline">Add Workout</span>
            </button>

            {/* Portal — render vào document.body, thoát khỏi mọi stacking context */}
            {mounted && open && createPortal(modalContent, document.body)}
        </>
    );
}

"use client";

import { useState } from "react";
import Image from "next/image";

const FILTERS = ["All", "Strength", "Yoga", "HIIT", "Cardio", "Pilates"];

export default function TrainersClient({ user, trainersDB }: { user: any, trainersDB: any[] }) {
    const [searchTerm, setSearchTerm] = useState("");
    const [activeFilter, setActiveFilter] = useState("All");

    // Format DB trainers to match the UI requirements
    const formattedTrainers = trainersDB.map((t) => {
        let tagColor = "bg-primary/90 text-white shadow-primary/20"; // default
        const specialtyLower = t.specialty ? t.specialty.toLowerCase() : "";

        if (specialtyLower.includes("yoga") || specialtyLower.includes("pilates")) {
            tagColor = "bg-purple-500/90 text-white shadow-purple-500/20";
        } else if (specialtyLower.includes("hiit")) {
            tagColor = "bg-orange-500/90 text-white shadow-orange-500/20";
        } else if (specialtyLower.includes("cardio")) {
            tagColor = "bg-blue-500/90 text-white shadow-blue-500/20";
        }

        // Mocking experience based on reviewCount since it's not in DB
        const experienceYears = Math.max(1, Math.floor((t.reviewCount || 0) / 10));

        return {
            id: t.id,
            name: t.user?.name || "Unknown Trainer",
            title: t.specialty || "Fitness Coach",
            specialty: t.specialty || "General",
            rating: typeof t.rating === 'number' ? t.rating : parseFloat(t.rating) || 5.0,
            experience: `${experienceYears} Years`,
            clients: `${t.reviewCount || 0}+`,
            imageUrl: t.imageUrl || "https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?q=80&w=2070&auto=format&fit=crop",
            tagColor
        };
    });

    const filteredTrainers = formattedTrainers.filter(trainer => {
        const matchesSearch = trainer.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
            trainer.specialty.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesFilter = activeFilter === "All" || trainer.specialty === activeFilter;
        return matchesSearch && matchesFilter;
    });

    return (
        <main className="flex-1 overflow-y-auto bg-background-dark relative">
            <div className="fixed inset-0 z-0 pointer-events-none">
                <div className="absolute -top-[10%] -right-[10%] h-[500px] w-[500px] rounded-full bg-primary/5 blur-[120px]"></div>
                <div className="absolute top-[40%] -left-[10%] h-[400px] w-[400px] rounded-full bg-purple-900/10 blur-[100px]"></div>
            </div>

            <div className="relative z-10 flex flex-col px-4 py-6 md:px-10 md:py-8 gap-8">
                <section className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                    <div>
                        <h3 className="text-3xl font-bold text-white tracking-tight">Meet Our Expert Trainers</h3>
                        <p className="text-text-muted mt-2 max-w-2xl">Browse our roster of certified professionals. Filter by specialty to find the perfect match for your goals.</p>
                    </div>

                    <div className="flex flex-wrap items-center gap-3">
                        <div className="relative group">
                            <span className="absolute left-3 top-1/2 -translate-y-1/2 material-symbols-outlined text-text-muted group-focus-within:text-white transition-colors">search</span>
                            <input
                                className="pl-10 pr-4 py-2.5 bg-surface-dark border border-border-dark rounded-xl text-white placeholder-text-muted focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary w-full md:w-64 transition-all"
                                placeholder="Search trainers..."
                                type="text"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                        {FILTERS.map(filter => (
                            <button
                                key={filter}
                                onClick={() => setActiveFilter(filter)}
                                className={`px-4 py-2.5 rounded-xl font-medium text-sm transition-colors ${activeFilter === filter
                                    ? "bg-primary text-white shadow-lg shadow-primary/20 hover:bg-primary-dark"
                                    : "bg-surface-dark border border-border-dark text-text-muted hover:text-white hover:border-white/20"
                                    }`}
                            >
                                {filter}
                            </button>
                        ))}
                    </div>
                </section>

                <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                    {filteredTrainers.length > 0 ? (
                        filteredTrainers.map(trainer => (
                            <div key={trainer.id} className="bg-surface-dark/60 backdrop-blur-md border border-white/5 rounded-2xl p-5 flex flex-col gap-4 group hover:border-primary/30 transition-all duration-300 hover:shadow-xl hover:shadow-primary/5">
                                <div className="relative w-full aspect-[4/5] rounded-xl overflow-hidden bg-surface-darker">
                                    <div
                                        className="absolute inset-0 bg-cover bg-center transition-transform duration-500 group-hover:scale-105"
                                        style={{ backgroundImage: `url('${trainer.imageUrl}')` }}
                                    ></div>
                                    <div className="absolute inset-0 bg-gradient-to-t from-background-dark via-transparent to-transparent opacity-80"></div>

                                    <div className="absolute top-3 right-3 bg-surface-darker/80 backdrop-blur-md px-2 py-1 rounded-lg flex items-center gap-1 border border-white/10">
                                        <span className="material-symbols-outlined text-yellow-400 text-[16px]">star</span>
                                        <span className="text-xs font-bold text-white">{trainer.rating.toFixed(1)}</span>
                                    </div>

                                    <div className="absolute bottom-3 left-3">
                                        <span className={`px-2.5 py-1 rounded-md text-[10px] font-bold uppercase tracking-wider backdrop-blur-sm ${trainer.tagColor}`}>
                                            {trainer.specialty}
                                        </span>
                                    </div>
                                </div>

                                <div>
                                    <h4 className="text-lg font-bold text-white group-hover:text-primary transition-colors">{trainer.name}</h4>
                                    <p className="text-sm text-text-muted">{trainer.title}</p>

                                    <div className="mt-3 flex items-center gap-4 text-xs text-text-muted border-t border-white/5 pt-3">
                                        <div className="flex items-center gap-1.5">
                                            <span className="material-symbols-outlined text-[16px]">verified</span>
                                            {trainer.experience} Exp.
                                        </div>
                                        <div className="flex items-center gap-1.5">
                                            <span className="material-symbols-outlined text-[16px]">person</span>
                                            {trainer.clients} Clients
                                        </div>
                                    </div>
                                </div>

                                <div className="grid grid-cols-2 gap-3 mt-auto">
                                    <button className="rounded-xl border border-border-dark bg-transparent py-2.5 text-xs font-bold text-white hover:bg-surface-dark transition-all">
                                        View Profile
                                    </button>
                                    <button className="rounded-xl bg-primary py-2.5 text-xs font-bold text-white shadow-lg shadow-primary/20 transition-all hover:bg-primary-dark hover:shadow-primary/40">
                                        Book Session
                                    </button>
                                </div>
                            </div>
                        ))
                    ) : (
                        <div className="col-span-full py-12 flex flex-col items-center justify-center text-text-muted">
                            <span className="material-symbols-outlined text-4xl mb-2 opacity-50">search_off</span>
                            <p>No trainers found matching your criteria.</p>
                            <button
                                onClick={() => { setSearchTerm(""); setActiveFilter("All"); }}
                                className="mt-4 text-primary hover:underline text-sm font-medium"
                            >
                                Clear filters
                            </button>
                        </div>
                    )}
                </section>
            </div>
        </main>
    );
}

